import "./styles/Threads.css";

export default function CommentSection({
                                           comments,
                                           user,
                                           newComment,
                                           setNewComment,
                                           onSubmit,
                                           onDelete,
                                           refreshComments
                                       }) {
    const role = String(user?.role || "").toUpperCase();
    const isAdmin = role === "ADMIN";
    const list = Array.isArray(comments) ? comments : [];

    function buildCommentTree(comments) {
        const map = new Map();
        const roots = [];

        comments.forEach(c => {
            map.set(c.id, { ...c, replies: [] });
        });

        map.forEach(c => {
            if (c.parentId) {
                const parent = map.get(c.parentId);
                if (parent) parent.replies.push(c);
            } else {
                roots.push(c);
            }
        });

        return roots;
    }


    async function toggleReaction(comment, type) {
        if (!user) return;

        const hasReacted = comment.reactions?.myReaction === type;
        const url = `http://localhost:8080/api/comments/${comment.id}/reactions?username=${user.username}`;

        try {
            if (hasReacted) {
                await fetch(url, { method: "DELETE" });
            } else {
                await fetch(url, {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ reactionType: type })
                });
            }

            if (typeof refreshComments === "function") {
                refreshComments();
            }
        } catch (err) {
            console.error("Failed to toggle reaction", err);
        }
    }


    return (
        <div className="comments-card">
            <h3>Comments</h3>

            {list.length === 0 && <p>No comments yet.</p>}

            <ul className="comment-list">
                {list.map(c => {
                    const canDelete =
                        user && (isAdmin || user.username === c.username);

                    return (
                        <li key={c.id} className="comment-item">
                            <div className="comment-header">
                                <div className="comment-meta">
                                    <strong>{c.username}</strong>
                                </div>
                                <span className="comment-time">
                                    {c.createdAt &&
                                        new Date(c.createdAt).toLocaleString()}
                                </span>
                            </div>

                            <div className="comment-body">
                                <div className="comment-text">
                                    {c.comment}
                                </div>

                                <div className="comment-actions">
                                    <button
                                        className={
                                            c.reactions?.myReaction === "LIKE"
                                                ? "reaction-btn active"
                                                : "reaction-btn"
                                        }
                                        onClick={() => toggleReaction(c, "LIKE")}
                                        disabled={!user}
                                        title="Like"
                                    >
                                        👍 {c.reactions?.counts?.LIKE || 0}
                                    </button>

                                    <button
                                        className={
                                            c.reactions?.myReaction === "DISLIKE"
                                                ? "reaction-btn active dislike"
                                                : "reaction-btn dislike"
                                        }
                                        onClick={() => toggleReaction(c, "DISLIKE")}
                                        disabled={!user}
                                        title="Dislike"
                                    >
                                        👎 {c.reactions?.counts?.DISLIKE || 0}
                                    </button>

                                    {canDelete && (
                                        <button
                                            className="delete-btn"
                                            onClick={() => onDelete(c.id)}
                                        >
                                            Delete
                                        </button>
                                    )}
                                </div>


                            </div>
                        </li>
                    );
                })}
            </ul>

            <form onSubmit={onSubmit} className="comment-form">
                <textarea
                    className="textarea"
                    value={newComment}
                    onChange={e => setNewComment(e.target.value)}
                    disabled={!user}
                    placeholder={
                        user ? "Write a comment…" : "Log in to comment"
                    }
                />
                <button
                    className="submit-btn"
                    type="submit"
                    disabled={!user || !newComment.trim()}
                >
                    Post Comment
                </button>
            </form>
        </div>
    );
}
